const input = $input.all();
const result = [];

input.forEach(item => {
  const { 
    product_series = '', 
    product_phase = '',
    product_model = '',
    beginseries, 
    endseries 
  } = item.json || {};

  if (typeof beginseries === 'number' && typeof endseries === 'number') {
    for (let i = beginseries; i <= endseries; i++) {
      // 1. 处理前缀部分（3位 = 1位系列 + 2位型号）
      const seriesStr = String(product_series).trim();
      const modelStr = String(product_model).padStart(2, '0').trim(); // 补零到2位
      const prefix = `${seriesStr}${modelStr}`.substring(0, 3); // 确保总长3位

      // 2. 处理阶段码（2位）
      const phaseStr = String(product_phase).trim();
      const phasePart = phaseStr.padEnd(2, 'Y').substring(0, 2);

      // 3. 生成基础序列号（格式: 前缀3 + 阶段码2 + 数字5）
      let sn = `${prefix}${phasePart}${String(i).padStart(5, '0')}`;

      // 4. 强制第4位为字母（索引3）
      if (!/[A-Za-z]/.test(sn[3])) {
        throw new Error(`第4位必须是字母，当前值: ${sn[3]} (完整SN: ${sn})`);
      }

      // 5. 截断确保10位
      sn = sn.substring(0, 10);
      result.push({ json: { sn } });
    }
  } else {
    console.error("Invalid beginseries or endseries:", beginseries, endseries);
  }
});

return result;

// 从 Execute Workflow 节点中提取所有数据。假设这里只有一个执行输出，且数据符合描述
const executeWorkflowData = $('查询工序').all().reduce((acc, item) => {
  if (Array.isArray(item.json.data)) {
    acc.push(...item.json.data);
  }
  return acc;
}, []);

// 从所有输入获得数据
const inputData = $input.all();

// 假定 executeWorkflowData 中的数据是可以映射到 inputData 的
const enhancedResults = inputData.map(inputItem => {
  const inputJson = inputItem.json;
  const bind_id = inputItem.json.retroid

  // 获取 Execute Workflow 数据中的第一个 entry 的 procedure_detail_id 和 history_procedure_id
  // 这是基于你给定的结构，确保这是你想要的对应关系。
  const procedureData = executeWorkflowData.find(item => item.procedure_detail_id !== undefined);

  if (procedureData) {
    // 将需要的字段合并到输入的元素中
    return {
      json: {
        ...inputJson,
        procedure_detail_id: procedureData.procedure_detail_id,
        history_procedure_id: procedureData.history_procedure_id,
        bind_id:bind_id
      }
    };
  }

  // 如果没有找到匹配的，返回未修改的 item
  return { 
    json: {
            ...inputJson,
            bind_id:bind_id    
          } 
         };
});

// 输出最终合并的结果
return enhancedResults;

