const items = $json.data;
const nonEmptyItems = items.filter(item => Object.keys(item).length > 0);

return [{ json: { nonEmptyCount: nonEmptyItems.length } }];

const existingIntervals = items.map(item => {
    // 兼容两种数据结构：优先取data内的值，没有则取顶层值
    const data = item.json.data || item.json;
    return {
      start: parseInt(data.beginseries, 10),  // 转换为数字
      end: parseInt(data.endseries, 10)      // 转换为数字
    };
  });

// 获取输入的区间（兼容字符串转数字）
  const inputData = $('Webhook').first().json.query
  const newInterval = {
    start: parseInt(inputData.BeginSeries, 10),
    end: parseInt(inputData.EndSeries, 10)
  };


// 优化后的重叠检测函数
  const findOverlaps = (existing, newInt) => {
    const overlaps = [];

    // 验证输入区间有效性
    if (isNaN(newInt.start) || isNaN(newInt.end)) {
      throw new Error("区间值必须是数字");
    }
    if (newInt.start > newInt.end) {
      throw new Error(`非法区间：起始值(${newInt.start})不能大于结束值(${newInt.end})`);
    }

    existing.forEach(item => {
      const overlapStart = Math.max(item.start, newInt.start);
      const overlapEnd = Math.min(item.end, newInt.end);

      if (overlapStart <= overlapEnd) {
        overlaps.push({
          existingInterval: `${item.start}-${item.end}`,
          overlapPart: `${overlapStart}-${overlapEnd}`,
          conflict: true,
          overlapLength: overlapEnd - overlapStart + 1
        });
      }
    });

    return overlaps.length > 0 ? overlaps : [{ 
      conflict: false,
      message: "新区间与现有区间无冲突" 
    }];
  };

  // 执行检测
  const result = findOverlaps(existingIntervals, newInterval);

  // 构建返回结果
  return [{
    json: {
      newInterval: `${newInterval.start}-${newInterval.end}`,
      overlaps: result,
      hasConflict: result[0].conflict,
      checkedIntervalCount: existingIntervals.length,
      // 调试信息（可选）
      //debug: {
        //receivedData: items.map(item => //item.json),
       // normalizedIntervals: //existingIntervals
     // }
    },
    pairedItem: items.map(item => item.pairedItem)
  }];

// 获取Webhook节点中的数据
const webhookQueryData = $('Webhook').first().json.query;

// 输入的数据
const inputData = $input.all();

// 判断输入数据是否为空对象，并设置默认值
const firstInputItem = inputData.length > 0 && Object.keys(inputData[0]).length > 0 ? inputData[0] : {
  json: {
    retroid_count: "0",
    product_quantity: 0
  }
};

// 从firstInputItem中获取json对象
const inputJson = firstInputItem.json || {};

// 计算generate_quantity
const generateQuantity = parseInt(webhookQueryData.EndSeries, 10) - parseInt(webhookQueryData.BeginSeries, 10) + 1; // +1 是因为系列是包括在内的

// 计算total数量，确保retroid_count是数值
const retroidCount = parseInt(inputJson.retroid_count || "0", 10);
const totalQuantity = retroidCount + generateQuantity;

// 合并结果并以数组形式返回
const resultArray = [
  {
    retroid_count: inputJson.retroid_count || "0",
    product_quantity: inputJson.product_quantity || 0,
    generate_quantity: generateQuantity,
    total: totalQuantity
  }
];

return resultArray;

